const body = $input.first().json.body;
let plan;
try {
  plan = typeof body.plan === 'string' ? JSON.parse(body.plan) : body.plan;
} catch (e) {
  throw new Error('Invalid plan JSON: ' + e.message);
}

const report_id = body.report_id || ('rpt_' + Date.now() + '_' + Math.random().toString(36).substring(2, 8));

const items = plan.steps.map(step => ({
  json: {
    report_id,
    plan_id: plan.plan_id || '',
    email: body.email,
    model: body.model || 'moonshotai/kimi-k2.5',
    total_steps: plan.total_steps || plan.steps.length,
    templateId: body.templateId || '',
    steps_only: body.steps_only === true,
    step: step
  }
}));

return items;

