  sql = sql.replace(/TRIM\("([^"]+)"\)\s*(?:!=|<>)\s*''/gi, '"$1" IS NOT NULL');
  sql = sql.replace(/TRIM\("([^"]+)"\)\s*=\s*''/gi, '"$1" IS NULL');
