{{ (function() {
  var step = $('Loop Over Steps').item.json.step;
  var reportId = $('Parse Plan & Generate Report ID').item.json.report_id.replace(/[^a-zA-Z0-9_]/g, '_');
  var sql = (step.query_strategy && (step.query_strategy.sql || step.query_strategy.logic)) || '';
  sql = sql.replace(/\bstep(\d+)\b/gi, function(m, n) {
    return 'n8n_data."tmp_' + reportId + '_step_' + n + '"';
  });
